        { referencia: "Atos 16:16-18", descricao: "referido apenas em Atos - a jovem com espírito de adivinhação." },
        { referencia: "Atos 16:19-24", descricao: "referido em 1 Tessalonicenses 2:2 - Paulo e Silas açoitados." },
        { referencia: "Atos 16:25-34", descricao: "referido em Salmo 119:62; Efésios 5:19 - cânticos à meia-noite." },
        { referencia: "Atos 16:31", descricao: "referido em João 3:16; Romanos 10:9 - fé em Cristo para salvação." },
        { referencia: "Atos 16:37-38", descricao: "referido em Atos 22:25-29 - direitos de cidadão romano." }
