        { referencia: "Atos 20:28", descricao: "referido em Efésios 1:7; Colossenses 1:14 - redenção pelo sangue." },
        { referencia: "Atos 20:35", descricao: "referido em Mateus 10:8; Lucas 6:38 - 'mais bem-aventurado dar do que receber'." }
